import threading
import time
import random

class ATM:
    def __init__(self, atm_id, initial_balance):
        self.atm_id = atm_id
        self.balance = initial_balance
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if amount <= self.balance:
                time.sleep(random.uniform(0.1, 0.5))  # Simulate transaction time
                self.balance -= amount
                print(f"ATM {self.atm_id}: Withdrawn {amount}. New balance: {self.balance}")
                return True
            else:
                print(f"ATM {self.atm_id}: Insufficient funds for withdrawal of {amount}.")
                return False

    def deposit(self, amount):
        with self.lock:
            time.sleep(random.uniform(0.1, 0.5))  # Simulate transaction time
            self.balance += amount
            print(f"ATM {self.atm_id}: Deposited {amount}. New balance: {self.balance}")

    def get_balance(self):
        with self.lock:
            return self.balance

class ATMController:
    def __init__(self):
        self.atms = {}

    def add_atm(self, atm):
        self.atms[atm.atm_id] = atm

    def perform_transaction(self, atm_id, transaction_type, amount):
        if atm_id in self.atms:
            atm = self.atms[atm_id]
            if transaction_type == 'withdraw':
                return atm.withdraw(amount)
            elif transaction_type == 'deposit':
                atm.deposit(amount)
                return True
        else:
            print(f"ATM {atm_id} not found.")
            return False

def simulate_user_activity(controller, atm_id):
    transaction_type = random.choice(['withdraw', 'deposit'])
    amount = random.randint(1, 100)
    if transaction_type == 'withdraw':
        controller.perform_transaction(atm_id, transaction_type, amount)
    else:
        controller.perform_transaction(atm_id, transaction_type, amount)

def main():
    controller = ATMController()
    atm1 = ATM(atm_id=1, initial_balance=1000)
    atm2 = ATM(atm_id=2, initial_balance=1000)
    controller.add_atm(atm1)
    controller.add_atm(atm2)

    threads = []
    for _ in range(10):
        atm_id = random.choice([1, 2])
        thread = threading.Thread(target=simulate_user_activity, args=(controller, atm_id))
        threads.append(thread)
        thread.start()

    for thread in threads:
        thread.join()

if __name__ == "__main__":
    main()

